import React from 'react';
import df from '../../styles/documentForm.module.css';

export interface ValidationErrorBannerProps {
  errors: string[];
  closed: boolean;
  expanded: boolean;
  onToggle: () => void;
  onClose: () => void;
  bannerId?: string;
}

export const ValidationErrorBanner: React.FC<ValidationErrorBannerProps> = ({
  errors,
  closed,
  expanded,
  onToggle,
  onClose,
  bannerId,
}) => {
  if (errors.length === 0 || closed) return null;
  return (
    <div className={df.errorBanner} id={bannerId} data-testid={bannerId}>
      <div className={df.errorBannerBody}>
        <div className={df.errorBannerHeader}>
          <strong>{errors.length} lỗi cần xử lý</strong>
          <div className={df.errorBannerActions}>
            <button type="button" className={df.errorBannerToggle} onClick={onToggle}>
              {expanded ? '▲ Thu gọn' : '▼ Chi tiết'}
            </button>
            <button type="button" className={df.errorBannerClose} onClick={onClose}>
              ✕
            </button>
          </div>
        </div>
        <div
          className={[
            df.errorListCollapse,
            expanded ? df.errorListCollapseExpanded : '',
          ].filter(Boolean).join(' ')}
          aria-hidden={!expanded}
        >
          <ul className={`${df.errorList} ${df.errorListInner}`}>
            {errors.map((e, i) => (
              <li key={`${i}-${e}`}>{e}</li>
            ))}
          </ul>
        </div>
      </div>
    </div>
  );
};
